import { NextRequest, NextResponse } from 'next/server';
import { logger } from '@/lib/logger';
export const dynamic = 'force-dynamic';

// GET /api/logs - Read logs
export async function GET(request: NextRequest) {
  try {
    const {
      searchParams
    } = new URL(request.url);
    const lines = parseInt(searchParams.get('lines') || '100', 10);
    const type = searchParams.get('type') === 'error' ? 'error' : 'app';
    const logs = logger.readLogs(lines, type);
    const size = logger.getLogSize(type);
    return NextResponse.json({
      success: true,
      data: {
        logs,
        lines: logs.length,
        size,
        type
      }
    });
  } catch (err) {
    return NextResponse.json({
      success: false,
      error: err instanceof Error ? err.message : 'Unknown error'
    }, {
      status: 500
    });
  }
}

// POST /api/logs - Clear logs or write log
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const {
      action,
      level,
      module,
      message,
      data,
      type
    } = body;
    if (action === 'clear') {
      logger.clearLogs(type || 'all');
      return NextResponse.json({
        success: true,
        message: 'Logs cleared'
      });
    }
    if (action === 'write') {
      const logLevel = level || 'info';
      const logModule = module || 'api';
      const logMessage = message || 'No message';
      switch (logLevel) {
        case 'debug':
          logger.debug(logModule, logMessage, data);
          break;
        case 'info':
          logger.info(logModule, logMessage, data);
          break;
        case 'warn':
          logger.warn(logModule, logMessage, data);
          break;
        case 'error':
          logger.error(logModule, logMessage, data);
          break;
        default:
          logger.info(logModule, logMessage, data);
      }
      return NextResponse.json({
        success: true,
        message: 'Log written'
      });
    }
    return NextResponse.json({
      success: false,
      error: 'Invalid action. Use "clear" or "write"'
    }, {
      status: 400
    });
  } catch (err) {
    return NextResponse.json({
      success: false,
      error: err instanceof Error ? err.message : 'Unknown error'
    }, {
      status: 500
    });
  }
}